[CmdletBinding()]param();$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;. (Join-Path $root 'tests/helpers/TypedStudioFixture.ps1');$work=Join-Path ([IO.Path]::GetTempPath()) ('context-'+[guid]::NewGuid().ToString('N'));New-Item -ItemType Directory $work|Out-Null
try{$p=New-TypedStudioFixture $work 'frontend' -ProductType 'landing-page' -Surfaces @('frontend-visible') -Approved -ExistingRepository;New-Item -ItemType Directory -Force (Join-Path $p '.studio/references/cards'),(Join-Path $p '.studio/reports')|Out-Null;'# card'|Set-Content (Join-Path $p '.studio/references/cards/REF-001.md');'old'|Set-Content (Join-Path $p '.studio/reports/superseded-old.md');& "$root/scripts/Resolve-SpecialistPlan.ps1" -ProjectRoot $p -OutputPath (Join-Path $p '.studio/reports/specialist-plan.json')|Out-Null;& "$root/scripts/context/compile_context.ps1" -ProjectRoot $p -Role frontend-builder|Out-Null;$m=Get-Content -Raw (Join-Path $p '.studio/runtime/context/frontend-builder.json')|ConvertFrom-Json;if($m.status -ne 'ready' -or $m.productType -ne 'landing-page' -or $m.surfaces -notcontains 'frontend-visible' -or $m.activeScope -contains 'ACTIVE_AND_DEFERRED_SCOPE.md'){throw 'Context manifest omitted actual typed state'};$b=New-TypedStudioFixture $work 'backend' -Surfaces @('backend-api') -Approved;& "$root/scripts/Resolve-SpecialistPlan.ps1" -ProjectRoot $b -OutputPath (Join-Path $b '.studio/reports/specialist-plan.json')|Out-Null;& "$root/scripts/context/compile_context.ps1" -ProjectRoot $b -Role backend-builder|Out-Null;$m=Get-Content -Raw (Join-Path $b '.studio/runtime/context/backend-builder.json')|ConvertFrom-Json;if($m.selectedRuleIds -match '^FQ-|^HT-|^LG-'){throw 'Backend context selected frontend rules'};& "$root/scripts/context/build_rule_route_index.ps1" -Check|Out-Null}finally{Remove-Item $work -Recurse -Force};Write-Host 'Context typed fixtures passed: parser, routing, compiler, and map regression checks; host runtime unverified.'
